"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { supabase } from '@/lib/supabase'
import FollowList from '@/components/FollowList'
import { useRouter } from "next/navigation";

type RequestOptions = RequestInit & { headers?: Record<string, string> };

interface ProfileUser {
  id?: string;
  profile_image_url?: string;
  full_name?: string;
  username?: string;
  is_seller?: boolean;
  bio?: string;
  location?: string;
  created_at?: string;
  total_donations?: number;
  eco_points?: number;
  co2_saved?: number;
  followers_count?: number;
  following_count?: number;
  is_following?: boolean;
}

interface Post {
  id: string;
  created_at: string;
  content?: string;
  likes_count?: number;
  comments_count?: number;
}

interface CommentItem {
  id: string;
  content: string;
  created_at: string;
  user_id?: string;
  user_full_name?: string;
  user_profile_image?: string;
}

interface Donation {
  id: string;
  device_type?: string;
  brand?: string;
  model?: string;
  eco_points_earned?: number;
  co2_saved?: number;
  status?: string;
  created_at: string;
}

export default function UserProfileClient({ id }: { id: string }) {
  const router = useRouter();
  const [user, setUser] = useState<any>(null);
  const [profileUser, setProfileUser] = useState<ProfileUser | null>(null);
  const [userPosts, setUserPosts] = useState<Post[]>([]);
  const [userDonations, setUserDonations] = useState<Donation[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isFollowing, setIsFollowing] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);

  const makeAuthenticatedRequest = async (url: string, options: RequestOptions = {}) => {
    const token = typeof window !== "undefined" ? localStorage.getItem("ecokonek_token") : null;
    if (!token) throw new Error("No authentication token");
    const res = await fetch(url, {
      ...options,
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
        ...(options.headers || {}),
      },
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return res.json();
  };

  // Social UI states
  const [likedPosts, setLikedPosts] = useState<Record<string, boolean>>({});
  const [loadingLikes, setLoadingLikes] = useState<Record<string, boolean>>({});
  const [commentsOpen, setCommentsOpen] = useState<Record<string, boolean>>({});
  const [commentsByPost, setCommentsByPost] = useState<Record<string, CommentItem[]>>({});
  const [commentInputs, setCommentInputs] = useState<Record<string, string>>({});
  const [loadingComments, setLoadingComments] = useState<Record<string, boolean>>({});

  // Followers / Following lists
  const [followersList, setFollowersList] = useState<any[]>([]);
  const [followingList, setFollowingList] = useState<any[]>([]);
  const [showFollowers, setShowFollowers] = useState(false);
  const [showFollowing, setShowFollowing] = useState(false);
  const [listLoading, setListLoading] = useState(false);

  const fetchLikedForPosts = async (posts: Post[]) => {
    try {
      const postIds = posts.map((p) => p.id)
      if (postIds.length === 0) return
      const res = await makeAuthenticatedRequest(`/api/supabase/functions/community-handler`, {
        method: 'POST',
        body: JSON.stringify({ action: 'get-liked-posts', postIds })
      })
      if (res?.success) {
  const likedSet: Record<string, boolean> = {};
  ;(res.liked || []).forEach((id: string) => { likedSet[id] = true })
        setLikedPosts(likedSet)
      }
    } catch (err) {
      // ignore - likes will default to false
      console.error('[fetchLikedForPosts] Error:', err)
    }
  }

  const fetchUserProfile = async (userId: string) => {
    setIsLoading(true);
    try {
      console.log('[UserProfile] Fetching profile for user:', userId);
      
      // Profile - using correct API route
      const profileData = await makeAuthenticatedRequest(
        `/api/supabase/functions/user-profile`,
        { method: "POST", body: JSON.stringify({ action: "get-user-profile", userId }) }
      );
      
      console.log('[UserProfile] Profile data:', profileData);
      
      if (profileData?.success && profileData?.profile) {
        setProfileUser(profileData.profile);
        setIsFollowing(profileData.profile.is_following || false);
      } else {
        console.error('[UserProfile] No profile data returned');
        setProfileUser(null);
      }

      // Posts - using correct API route
      const postsData = await makeAuthenticatedRequest(
        `/api/supabase/functions/community-handler`,
        { method: "POST", body: JSON.stringify({ action: "get-user-posts", userId }) }
      );
      const posts = postsData?.posts || []
      setUserPosts(posts);
      // Initialize liked flags for posts (best-effort)
      await fetchLikedForPosts(posts)

      // Donations - using correct API route
      const donationsData = await makeAuthenticatedRequest(
        `/api/supabase/functions/donation-handler`,
        { method: "POST", body: JSON.stringify({ action: "get-user-donations", userId }) }
      );
      setUserDonations(donationsData?.donations || []);
    } catch (err) {
      console.error("[UserProfile] Failed to load profile page data", err);
      setProfileUser(null);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeletePost = async (postId: string) => {
    if (!postId) return;
    if (!confirm('Are you sure you want to delete this post? This action cannot be undone.')) return;

    const prev = userPosts.map(p => ({ ...p }));
    // optimistic remove
    setUserPosts((prevPosts) => prevPosts.filter(p => p.id !== postId));

    try {
      const data = await makeAuthenticatedRequest(`/api/supabase/functions/community-handler`, {
        method: 'POST',
        body: JSON.stringify({ action: 'delete-post', postId })
      });

      if (!data || !data.success) {
        // revert
        setUserPosts(prev);
        alert(data?.error || 'Failed to delete post');
        return;
      }

      // success - postsCache is invalidated server-side; nothing more needed
    } catch (err) {
      console.error('[handleDeletePost] Error deleting post:', err);
      setUserPosts(prev);
      alert('Failed to delete post. Please try again.');
    }
  };

  const handleFollowToggle = async () => {
    if (!profileUser?.id || isFollowLoading) return;
    
    // Prevent following yourself
    if (user?.id === profileUser?.id) {
      console.warn('[handleFollowToggle] Cannot follow yourself');
      return;
    }
    
    setIsFollowLoading(true);
    try {
      const action = isFollowing ? 'unfollow-user' : 'follow-user';
      const data = await makeAuthenticatedRequest(
        `/api/supabase/functions/user-profile`,
        { 
          method: "POST", 
          body: JSON.stringify({ 
            action, 
            targetUserId: profileUser.id 
          }) 
        }
      );

      if (data?.success) {
        setIsFollowing(!isFollowing);
        
        // Update follower count optimistically
        setProfileUser(prev => prev ? {
          ...prev,
          followers_count: (prev.followers_count || 0) + (isFollowing ? -1 : 1)
        } : prev);
      }
    } catch (error) {
      console.error('[handleFollowToggle] Error:', error);
    } finally {
      setIsFollowLoading(false);
    }
  };

  // Like / Comment helpers
  const handleToggleLike = async (postId: string) => {
    if (!postId) return
    // optimistic
    setLoadingLikes(prev => ({ ...prev, [postId]: true }))
    const currentlyLiked = !!likedPosts[postId]
    setLikedPosts(prev => ({ ...prev, [postId]: !currentlyLiked }))
    setUserPosts(prev => prev.map(p => p.id === postId ? { ...p, likes_count: (p.likes_count || 0) + (currentlyLiked ? -1 : 1) } : p))

    try {
      const res = await makeAuthenticatedRequest(`/api/supabase/functions/community-handler`, {
        method: 'POST',
        body: JSON.stringify({ action: 'like-post', postId })
      })
      if (res?.success) {
        // reconcile authoritative likes_count and liked flag
        setUserPosts(prev => prev.map(p => p.id === postId ? { ...p, likes_count: res.likes_count ?? p.likes_count } : p))
        setLikedPosts(prev => ({ ...prev, [postId]: !!res.liked }))
      }
    } catch (err) {
      console.error('[handleToggleLike] Error:', err)
      // revert optimistic
      setLikedPosts(prev => ({ ...prev, [postId]: currentlyLiked }))
      setUserPosts(prev => prev.map(p => p.id === postId ? { ...p, likes_count: (p.likes_count || 0) + (currentlyLiked ? 1 : -1) } : p))
    } finally {
      setLoadingLikes(prev => ({ ...prev, [postId]: false }))
    }
  }

  const fetchCommentsForPost = async (postId: string) => {
    setLoadingComments(prev => ({ ...prev, [postId]: true }))
    try {
      const res = await makeAuthenticatedRequest(`/api/supabase/functions/community-handler`, {
        method: 'POST',
        body: JSON.stringify({ action: 'get-post-comments', postId })
      })
      if (res?.success) {
        setCommentsByPost(prev => ({ ...prev, [postId]: res.comments || [] }))
      }
    } catch (err) {
      console.error('[fetchCommentsForPost] Error:', err)
    } finally {
      setLoadingComments(prev => ({ ...prev, [postId]: false }))
    }
  }

  const toggleComments = async (postId: string) => {
    setCommentsOpen(prev => ({ ...prev, [postId]: !prev[postId] }))
    if (!commentsByPost[postId]) {
      await fetchCommentsForPost(postId)
    }
  }

  const submitCommentForPost = async (postId: string) => {
    const content = (commentInputs[postId] || '').trim()
    if (!content) return
    try {
      const res = await makeAuthenticatedRequest(`/api/supabase/functions/community-handler`, {
        method: 'POST',
        body: JSON.stringify({ action: 'create-comment', postId, content })
      })
      if (res?.success) {
        // append new comment optimistically
        const newComment = res.comment
        setCommentsByPost(prev => ({ ...prev, [postId]: [...(prev[postId] || []), newComment] }))
        setCommentInputs(prev => ({ ...prev, [postId]: '' }))
        // update comments_count on post
        setUserPosts(prev => prev.map(p => p.id === postId ? { ...p, comments_count: res.comments_count ?? (p.comments_count || 0) + 1 } : p))
      }
    } catch (err) {
      console.error('[submitCommentForPost] Error:', err)
      alert('Failed to post comment')
    }
  }

  // Followers / Following lists
  const fetchFollowers = async () => {
    if (!profileUser?.id) return
    setListLoading(true)
    setShowFollowers(true) // Show modal immediately with loading state
    try {
      // Try RPC first
      const { data, error } = await supabase.rpc('get_followers_list', { profile_user_id: profileUser.id })
      
      if (error) {
        console.log('[fetchFollowers] RPC error, trying API fallback:', error.message)
        // Fallback to API
        const res = await makeAuthenticatedRequest('/api/supabase/functions/user-profile', {
          method: 'POST',
          body: JSON.stringify({ action: 'get-followers', userId: profileUser.id })
        })
        if (res?.success && Array.isArray(res.followers)) {
          setFollowersList(res.followers.map((r: any) => ({
            id: r.id,
            username: r.username || '',
            full_name: r.full_name || r.username || '',
            profile_image_url: r.profile_image_url || r.avatar_url || null,
            is_following: !!r.is_following
          })))
        } else {
          console.error('[fetchFollowers] API fallback also failed')
          setFollowersList([])
        }
      } else {
        // RPC succeeded - map returned rows
        const mapped = ((data as any[]) || []).map((r: any) => ({
          id: r.id,
          username: r.username || '',
          full_name: r.full_name || r.username || '',
          profile_image_url: r.avatar_url || r.profile_image_url || null,
          is_following: !!r.is_following
        }))
        setFollowersList(mapped)
      }
    } catch (err) {
      console.error('[fetchFollowers] Error:', err)
      setFollowersList([])
    } finally {
      setListLoading(false)
    }
  }

  const fetchFollowing = async () => {
    if (!profileUser?.id) return
    setListLoading(true)
    setShowFollowing(true) // Show modal immediately with loading state
    try {
      // Try RPC first
      const { data, error } = await supabase.rpc('get_following_list', { profile_user_id: profileUser.id })
      
      if (error) {
        console.log('[fetchFollowing] RPC error, trying API fallback:', error.message)
        // Fallback to API
        const res = await makeAuthenticatedRequest('/api/supabase/functions/user-profile', {
          method: 'POST',
          body: JSON.stringify({ action: 'get-following', userId: profileUser.id })
        })
        if (res?.success && Array.isArray(res.following)) {
          setFollowingList(res.following.map((r: any) => ({
            id: r.id,
            username: r.username || '',
            full_name: r.full_name || r.username || '',
            profile_image_url: r.profile_image_url || r.avatar_url || null,
            is_following: !!r.is_following
          })))
        } else {
          console.error('[fetchFollowing] API fallback also failed')
          setFollowingList([])
        }
      } else {
        // RPC succeeded - map returned rows
        const mapped = ((data as any[]) || []).map((r: any) => ({
          id: r.id,
          username: r.username || '',
          full_name: r.full_name || r.username || '',
          profile_image_url: r.avatar_url || r.profile_image_url || null,
          is_following: !!r.is_following
        }))
        setFollowingList(mapped)
      }
    } catch (err) {
      console.error('[fetchFollowing] Error:', err)
      setFollowingList([])
    } finally {
      setListLoading(false)
    }
  }

  // Modal keyboard/interaction improvements: close on Escape and autofocus first link
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        if (showFollowers) setShowFollowers(false)
        if (showFollowing) setShowFollowing(false)
      }
    }
    if (showFollowers || showFollowing) {
      document.addEventListener('keydown', onKey)
      // autofocus first link in modal after a tick
      setTimeout(() => {
        const modal = document.querySelector('.follow-modal') as HTMLElement | null
        if (modal) {
          const firstLink = modal.querySelector('a') as HTMLElement | null
          if (firstLink) firstLink.focus()
        }
      }, 0)
    }
    return () => document.removeEventListener('keydown', onKey)
  }, [showFollowers, showFollowing])

  const handleListFollowToggle = async (targetId: string, currentlyFollowing: boolean, listType: 'followers' | 'following') => {
    try {
      const action = currentlyFollowing ? 'unfollow-user' : 'follow-user'
      const res = await makeAuthenticatedRequest(`/api/supabase/functions/user-profile`, {
        method: 'POST',
        body: JSON.stringify({ action, targetUserId: targetId })
      })
      if (res?.success) {
        // update the specific list to reflect new follow state
        if (listType === 'followers') {
          setFollowersList(prev => prev.map(u => u.id === targetId ? { ...u, is_following: !currentlyFollowing } : u))
        } else {
          setFollowingList(prev => prev.map(u => u.id === targetId ? { ...u, is_following: !currentlyFollowing } : u))
        }
      }
    } catch (err) {
      console.error('[handleListFollowToggle] Error:', err)
    }
  }

  useEffect(() => {
    // Basic auth gate from localStorage
    const token = typeof window !== "undefined" ? localStorage.getItem("ecokonek_token") : null;
    const userData = typeof window !== "undefined" ? localStorage.getItem("ecokonek_user") : null;
    if (!token || !userData) {
      router.push("/login");
      return;
    }
    try {
      setUser(JSON.parse(userData));
    } catch {
      // If parsing fails, force login
      router.push("/login");
      return;
    }
    if (id) fetchUserProfile(id);
  }, [id, router]);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-green-50 to-emerald-50 flex items-center justify-center">
        <div className="text-gray-500">Loading profile…</div>
      </div>
    );
  }

  if (!profileUser) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-green-50 to-emerald-50 flex items-center justify-center">
        <div className="text-center">
          <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <i className="ri-user-line text-gray-400 text-2xl"></i>
          </div>
          <h2 className="text-xl font-semibold text-gray-800 mb-2">Profile not found</h2>
          <p className="text-gray-600 mb-6">This user may be private or does not exist.</p>
          <Link href="/community" className="inline-flex items-center gap-2 text-green-600 hover:text-green-700">
            <i className="ri-arrow-left-line"></i>
            Back to Community
          </Link>
        </div>
        {/* Followers Modal */}
        {showFollowers && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div
              className="absolute inset-0 bg-black/40 cursor-pointer hover:bg-black/50 transition-colors"
              onClick={() => setShowFollowers(false)}
            ></div>
            <div
              role="dialog"
              aria-modal="true"
              tabIndex={-1}
              className="follow-modal relative bg-white rounded-xl shadow-2xl w-full max-w-md p-6 focus:outline-none animate-in fade-in zoom-in-95 duration-200"
            >
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-semibold text-gray-900">Followers</h3>
                <button 
                  onClick={() => setShowFollowers(false)} 
                  className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500 hover:text-gray-700"
                  aria-label="Close"
                >
                  <i className="ri-close-line text-xl"></i>
                </button>
              </div>
              <div className="space-y-3 max-h-80 overflow-auto">
                {listLoading ? (
                  <div className="flex items-center justify-center py-8">
                    <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-green-600"></div>
                    <span className="ml-2 text-gray-500">Loading…</span>
                  </div>
                ) : (
                  <FollowList
                    items={followersList}
                    listType="followers"
                    onToggleFollow={(targetId, currentlyFollowing) => handleListFollowToggle(targetId, currentlyFollowing, 'followers')}
                  />
                )}
              </div>
            </div>
          </div>
        )}

        {/* Following Modal */}
        {showFollowing && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div
              className="absolute inset-0 bg-black/40 cursor-pointer hover:bg-black/50 transition-colors"
              onClick={() => setShowFollowing(false)}
            ></div>
            <div
              role="dialog"
              aria-modal="true"
              tabIndex={-1}
              className="follow-modal relative bg-white rounded-xl shadow-2xl w-full max-w-md p-6 focus:outline-none animate-in fade-in zoom-in-95 duration-200"
            >
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-semibold text-gray-900">Following</h3>
                <button 
                  onClick={() => setShowFollowing(false)} 
                  className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500 hover:text-gray-700"
                  aria-label="Close"
                >
                  <i className="ri-close-line text-xl"></i>
                </button>
              </div>
              <div className="space-y-3 max-h-80 overflow-auto">
                {listLoading ? (
                  <div className="flex items-center justify-center py-8">
                    <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-green-600"></div>
                    <span className="ml-2 text-gray-500">Loading…</span>
                  </div>
                ) : (
                  <FollowList
                    items={followingList}
                    listType="following"
                    onToggleFollow={(targetId, currentlyFollowing) => handleListFollowToggle(targetId, currentlyFollowing, 'following')}
                  />
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-50 to-emerald-50">
      <div className="container mx-auto px-6 py-8 max-w-6xl">
        <div className="mb-6">
          <Link
            href="/community"
            className="flex items-center gap-2 text-gray-600 hover:text-green-600 transition-colors cursor-pointer"
          >
            <i className="ri-arrow-left-line"></i>
            <span>Back to Community</span>
          </Link>
        </div>

        <div className="bg-white rounded-2xl shadow-lg p-8 mb-8 border border-gray-100">
          <div className="flex items-start gap-6">
            <div className="w-20 h-20 rounded-full bg-gradient-to-br from-green-400 to-emerald-500 flex items-center justify-center text-2xl overflow-hidden flex-shrink-0">
              {profileUser?.profile_image_url ? (
                <img 
                  src={profileUser.profile_image_url} 
                  alt={profileUser.full_name || profileUser.username || 'Profile'} 
                  className="w-full h-full object-cover"
                />
              ) : (
                <i className="ri-user-line text-white"></i>
              )}
            </div>
            <div className="flex-1">
              <div className="flex items-start justify-between">
                <div>
                  <h1 className="text-2xl font-bold text-gray-800">
                    {profileUser?.full_name || profileUser?.username}
                  </h1>
                  <p className="text-gray-600">@{profileUser?.username}</p>
                  {profileUser?.is_seller && (
                    <span className="mt-2 inline-block bg-blue-100 text-blue-600 text-xs px-3 py-1 rounded-full font-medium">
                      <i className="ri-store-line mr-1"></i>
                      Verified Seller
                    </span>
                  )}
                </div>
                {/* Only show Follow button if viewing someone else's profile */}
                {user?.id !== profileUser?.id && (
                  <button
                    className={`px-6 py-2 rounded-lg font-medium transition-colors cursor-pointer ${
                      isFollowing 
                        ? 'bg-gray-200 hover:bg-gray-300 text-gray-700' 
                        : 'bg-green-500 hover:bg-green-600 text-white'
                    } ${isFollowLoading ? 'opacity-50 cursor-not-allowed' : ''}`}
                    onClick={handleFollowToggle}
                    disabled={isFollowLoading}
                  >
                    <i className={`${isFollowing ? 'ri-user-unfollow-line' : 'ri-user-add-line'} mr-2`}></i>
                    {isFollowLoading ? 'Loading...' : isFollowing ? 'Following' : 'Follow'}
                  </button>
                )}
                {/* Show "This is you" badge when viewing own profile */}
                {user?.id === profileUser?.id && (
                  <span className="px-4 py-2 bg-gray-100 text-gray-600 rounded-lg text-sm font-medium">
                    <i className="ri-user-line mr-2"></i>
                    This is you
                  </span>
                )}
              </div>
              {profileUser?.bio && (
                <p className="mt-4 text-gray-700">{profileUser.bio}</p>
              )}
              
              {/* Follower/Following Stats (clickable) */}
              <div className="flex items-center gap-6 mt-4 text-sm">
                <button onClick={fetchFollowers} className="flex items-center gap-2">
                  <span className="font-bold text-gray-800">{profileUser?.followers_count || 0}</span>
                  <span className="text-gray-600">Followers</span>
                </button>
                <button onClick={fetchFollowing} className="flex items-center gap-2">
                  <span className="font-bold text-gray-800">{profileUser?.following_count || 0}</span>
                  <span className="text-gray-600">Following</span>
                </button>
              </div>
              
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-6">
                <div className="bg-gray-50 rounded-xl p-4">
                  <p className="text-sm text-gray-500">Eco Points</p>
                  <p className="text-xl font-bold text-gray-800">{profileUser?.eco_points ?? 0}</p>
                </div>
                <div className="bg-gray-50 rounded-xl p-4">
                  <p className="text-sm text-gray-500">Total Donations</p>
                  <p className="text-xl font-bold text-gray-800">{profileUser?.total_donations ?? 0}</p>
                </div>
                <div className="bg-gray-50 rounded-xl p-4">
                  <p className="text-sm text-gray-500">CO₂ Saved</p>
                  <p className="text-xl font-bold text-gray-800">{profileUser?.co2_saved ?? 0} kg</p>
                </div>
                <div className="bg-gray-50 rounded-xl p-4">
                  <p className="text-sm text-gray-500">Member Since</p>
                  <p className="text-xl font-bold text-gray-800">
                    {profileUser?.created_at ? new Date(profileUser.created_at).toLocaleDateString() : "-"}
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2">
            <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
              <div className="p-6 border-b border-gray-100">
                <h2 className="text-lg font-semibold text-gray-800">Posts</h2>
              </div>
              <div className="p-6">
                <div className="space-y-6">
                  {userPosts.length > 0 ? (
                    userPosts.map((post) => (
                      <div key={post.id} className="border border-gray-200 rounded-xl p-6">
                        <div className="flex items-center justify-between mb-3">
                          <div className="text-gray-500 text-sm">
                            {new Date(post.created_at).toLocaleString()}
                          </div>
                          <div className="flex items-center gap-4 text-gray-500">
                            <button
                              onClick={() => handleToggleLike(post.id)}
                              disabled={!!loadingLikes[post.id]}
                              className="flex items-center gap-2 px-2 py-1 rounded-md hover:bg-gray-50"
                            >
                              <i className={`${likedPosts[post.id] ? 'ri-heart-fill text-red-500' : 'ri-heart-line'}`}></i>
                              <span>{post.likes_count ?? 0}</span>
                            </button>
                            <button
                              onClick={() => toggleComments(post.id)}
                              className="flex items-center gap-2 px-2 py-1 rounded-md hover:bg-gray-50"
                            >
                              <i className="ri-chat-3-line"></i>
                              <span>{post.comments_count ?? 0}</span>
                            </button>
                          </div>
                        </div>
                        <p className="text-gray-700">{post.content}</p>

                        {/* Comments area (expandable) */}
                        {commentsOpen[post.id] && (
                          <div className="mt-4 border-t pt-4">
                            <div className="space-y-3 max-h-64 overflow-auto pr-2">
                              {(commentsByPost[post.id] || []).length > 0 ? (
                                (commentsByPost[post.id] || []).map((c) => (
                                  <div key={c.id} className="flex items-start gap-3">
                                    <div className="w-8 h-8 rounded-full bg-gray-100 overflow-hidden">
                                      {c.user_profile_image ? (
                                        <img src={c.user_profile_image} alt={c.user_full_name} className="w-full h-full object-cover" />
                                      ) : (
                                        <i className="ri-user-line text-gray-400"></i>
                                      )}
                                    </div>
                                    <div>
                                      <div className="text-sm font-medium text-gray-800">{c.user_full_name || c.user_id}</div>
                                      <div className="text-sm text-gray-700">{c.content}</div>
                                      <div className="text-xs text-gray-400">{new Date(c.created_at).toLocaleString()}</div>
                                    </div>
                                  </div>
                                ))
                              ) : (
                                <div className="text-gray-500">No comments yet</div>
                              )}
                            </div>

                            <div className="mt-4 flex gap-2">
                              <input
                                value={commentInputs[post.id] || ''}
                                onChange={(e) => setCommentInputs(prev => ({ ...prev, [post.id]: e.target.value }))}
                                className="flex-1 rounded-lg border px-3 py-2"
                                placeholder="Write a comment..."
                              />
                              <button
                                onClick={() => submitCommentForPost(post.id)}
                                className="bg-green-500 text-white px-4 py-2 rounded-lg"
                              >
                                Comment
                              </button>
                            </div>
                          </div>
                        )}

                        {user?.id === profileUser?.id && (
                          <div className="mt-4 text-right">
                            <button
                              onClick={() => handleDeletePost(post.id)}
                              className="text-sm text-red-600 hover:underline"
                            >
                              Delete Post
                            </button>
                          </div>
                        )}
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-12 text-gray-500">No posts yet</div>
                  )}
                </div>
              </div>
            </div>
          </div>

          <div className="lg:col-span-1">
            <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
              <div className="p-6 border-b border-gray-100">
                <h2 className="text-lg font-semibold text-gray-800">Recent Donations</h2>
              </div>
              <div className="p-6">
                <div className="space-y-4">
                  {userDonations.length > 0 ? (
                    userDonations.map((donation) => (
                      <div key={donation.id} className="border border-gray-200 rounded-xl p-4">
                        <div className="flex items-center justify-between">
                          <div>
                            <p className="font-medium text-gray-800">
                              {donation.device_type || "Device"}
                            </p>
                            <p className="text-sm text-gray-500">
                              {donation.brand} {donation.model}
                            </p>
                            {donation.status && (
                              <span className={`text-xs px-2 py-1 rounded-full mt-1 inline-block ${
                                donation.status === 'accepted' || donation.status === 'approved' 
                                  ? 'bg-green-100 text-green-600' 
                                  : donation.status === 'pending'
                                  ? 'bg-orange-100 text-orange-600'
                                  : donation.status === 'rejected'
                                  ? 'bg-red-100 text-red-600'
                                  : 'bg-gray-100 text-gray-600'
                              }`}>
                                {donation.status}
                              </span>
                            )}
                          </div>
                          <div className="text-right">
                            <p className="text-green-600 font-medium">
                              +{donation.eco_points_earned ?? 0} pts
                            </p>
                            <p className="text-sm text-gray-500">
                              {new Date(donation.created_at).toLocaleDateString()}
                            </p>
                          </div>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-8 text-gray-500">No donations yet</div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
        {/* Followers Modal (main view) */}
        {showFollowers && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div 
              className="absolute inset-0 bg-black/40 cursor-pointer hover:bg-black/50 transition-colors" 
              onClick={() => setShowFollowers(false)}
            ></div>
            <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-md p-6 animate-in fade-in zoom-in-95 duration-200">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-semibold text-gray-900">Followers</h3>
                <button 
                  onClick={() => setShowFollowers(false)} 
                  className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500 hover:text-gray-700"
                  aria-label="Close"
                >
                  <i className="ri-close-line text-xl"></i>
                </button>
              </div>
              <div className="space-y-3 max-h-80 overflow-auto">
                {listLoading ? (
                  <div className="flex items-center justify-center py-8">
                    <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-green-600"></div>
                    <span className="ml-2 text-gray-500">Loading…</span>
                  </div>
                ) : (
                  <FollowList
                    items={followersList}
                    listType="followers"
                    onToggleFollow={(targetId, currentlyFollowing) => handleListFollowToggle(targetId, currentlyFollowing, 'followers')}
                  />
                )}
              </div>
            </div>
          </div>
        )}

        {/* Following Modal (main view) */}
        {showFollowing && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div 
              className="absolute inset-0 bg-black/40 cursor-pointer hover:bg-black/50 transition-colors" 
              onClick={() => setShowFollowing(false)}
            ></div>
            <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-md p-6 animate-in fade-in zoom-in-95 duration-200">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-semibold text-gray-900">Following</h3>
                <button 
                  onClick={() => setShowFollowing(false)} 
                  className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500 hover:text-gray-700"
                  aria-label="Close"
                >
                  <i className="ri-close-line text-xl"></i>
                </button>
              </div>
              <div className="space-y-3 max-h-80 overflow-auto">
                {listLoading ? (
                  <div className="flex items-center justify-center py-8">
                    <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-green-600"></div>
                    <span className="ml-2 text-gray-500">Loading…</span>
                  </div>
                ) : (
                  <FollowList
                    items={followingList}
                    listType="following"
                    onToggleFollow={(targetId, currentlyFollowing) => handleListFollowToggle(targetId, currentlyFollowing, 'following')}
                  />
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
