"use client"

import React from 'react'
import Link from 'next/link'

type FollowItem = {
  id: string
  username?: string
  full_name?: string
  profile_image_url?: string
  is_following?: boolean
}

type Props = {
  items: FollowItem[]
  listType: 'followers' | 'following'
  onToggleFollow?: (targetId: string, currentlyFollowing: boolean) => void
}

export default function FollowList({ items, listType, onToggleFollow }: Props) {
  return (
    <div className="space-y-3 max-h-72 overflow-auto">
      {items.length === 0 ? (
        <div className="text-gray-500">No {listType === 'followers' ? 'followers' : 'following'} found</div>
      ) : (
        items.map((f) => (
          <div key={f.id} className="flex items-center justify-between">
            <Link href={`/community/profile/${f.id}`} className="flex items-center gap-3 py-2">
              <div className="w-10 h-10 rounded-full overflow-hidden bg-gray-100 flex-shrink-0">
                {f.profile_image_url ? (
                  // eslint-disable-next-line @next/next/no-img-element
                  <img src={f.profile_image_url} alt={f.full_name || f.username} className="w-full h-full object-cover" />
                ) : (
                  <i className="ri-user-line text-gray-400 flex items-center justify-center w-full h-full"></i>
                )}
              </div>
              <div>
                <div className="text-sm font-medium text-gray-800">{f.full_name || f.username}</div>
                <div className="text-xs text-gray-400">@{f.username}</div>
              </div>
            </Link>

            {typeof onToggleFollow === 'function' && (
              <div>
                <button
                  onClick={() => onToggleFollow(f.id, !!f.is_following)}
                  className={`px-3 py-1 rounded-md text-sm ${f.is_following ? 'bg-gray-200' : 'bg-green-500 text-white'}`}
                >
                  {f.is_following ? 'Following' : 'Follow'}
                </button>
              </div>
            )}
          </div>
        ))
      )}
    </div>
  )
}
